                        <div class="quote-line">${cardMeaning}</div>
                        <div class="gossip-line">${cardComment}</div>
                    </div>
                `;
            } else
         if (mode === 'memory') {
            // --- 全新：为 memory 模式构建复古窗口DOM ---
            wrapper.innerHTML = `
