        } else {
            // 默认的静态卡片结构
            wrapper.innerHTML = `
                <div class="line-1">${lines[0] || ''}</div>
                <div class="line-2">${lines[1] || ''}</div>
                <div class="line-3">${lines[2] || ''}</div>
                <div class="line-4">${lines[3] || ''}</div>
            `;
        }
        cardContainer.appendChild(wrapper);
    }
});
