    max-height: 110px;
    transform: rotate(-2deg);
    border-radius: 2px;

    /* Animation */
    transition: 
        max-height 0.8s cubic-bezier(0.25, 1, 0.5, 1), 
        padding 0.8s ease,
        transform 0.4s ease,
        background-color 0.5s ease,
        color 0.5s ease;
}

/* Expanded State */
.setlist-card.is-open {
    max-height: 2000px; /* Large enough to fit content */
    padding: 60px 25px 60px; /* Add top/bottom padding only when open */
    transform: rotate(0deg) scale(1.01);
    box-shadow: 0 15px 30px rgba(0,0,0,0.25);
}

/* --- Fold Visuals --- */
/* The fold crease shadow */
.setlist-card::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    width: 100%;
    height: 40px;
