.tape-tr { top: -8px; right: -20px; transform: rotate(25deg); width: 60px; }
/* Bottom tapes hidden when folded, visible when open */
.tape-bl, .tape-bc {
    opacity: 0;
    transition: opacity 0.5s 0.3s; /* Delay appearance */
}
.setlist-card.is-open .tape-bl, 
.setlist-card.is-open .tape-bc {
