}
.tape-bl { bottom: -10px; left: -15px; transform: rotate(-40deg); width: 50px; }
.tape-bc { bottom: -12px; left: 50%; transform: translateX(-50%) rotate(2deg); width: 100px; }

/* --- Typography --- */
