<script>
document.addEventListener('DOMContentLoaded', () => {
    const rawEl = document.getElementById('rawData');
    const contentEl = document.getElementById('contentContainer');
    const sourceEl = document.getElementById('sourceText');
    const card = document.getElementById('setlistCard');
    const btn = document.getElementById('themeBtn');

    function splitLines(s) {
        return s ? s.trim().split('\n')
            .map(v => v.trim().replace(/^(["“「])(.*)\1$/, '$2'))
            .filter(Boolean) : [];
    }

    function parsePrologue(html) {
        if (!html || !html.trim()) return null;
        const lines = html.trim().split('\n');
        const last = lines[lines.length - 1]?.trim() || '';
        let source = '', body = html.trim();
        if (/^[—―─-]/.test(last)) {
            source = last.replace(/^[—―─-]\s*/, '');
            lines.pop();
            body = lines.join('\n').trim();
        }
        const parts = body.split(/<hr\s*\/?>/i);
        const partA = parts[0], partB = parts[1];
        return {
            original: partB ? splitLines(partA) : [],
            translation: partB ? splitLines(partB) : splitLines(partA),
            source: source
        };
    }

    function render() {
        const data = parsePrologue(rawEl.innerHTML);
        contentEl.innerHTML = '';
        sourceEl.textContent = '';
        if (data) {
            data.original.forEach(line => {
                const p = document.createElement('div');
                p.className = 'original-line';
                p.textContent = line;
                contentEl.appendChild(p);
            });
            data.translation.forEach(line => {
                const p = document.createElement('div');
                p.className = 'translation-line';
                p.textContent = line;
                contentEl.appendChild(p);
            });
            if (data.source) sourceEl.textContent = data.source;
        }
    }

    // --- Interaction Logic ---

    // 1. Fold/Unfold Logic
    card.addEventListener('click', (e) => {
        // Don't toggle if clicking the theme button
        if (btn.contains(e.target)) return;

        card.classList.toggle('is-open');

        // Optional: Scroll slightly if expanding makes it go off screen
        if(card.classList.contains('is-open')){
             // logic if needed
        }
    });

    // 2. Theme Logic
    function toggleTheme() {
        card.classList.toggle('dark-mode');
        const isDark = card.classList.contains('dark-mode');
        localStorage.setItem('rockSetlistTheme', isDark ? 'dark' : 'light');
    }
    const savedTheme = localStorage.getItem('rockSetlistTheme');
    if (savedTheme === 'dark') card.classList.add('dark-mode');

    btn.addEventListener('click', (e) => {
        e.stopPropagation(); // Stop bubbling to card click
        toggleTheme();
    });

    render();
});
</script>
