<!DOCTYPE html>
<html lang="zh-CN">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Rock Player Summary</title>
<style>
/* --- Fonts --- */
@import url('https://fonts.googleapis.com/css2?family=New+Rocker&family=Courier+Prime:ital,wght@0,400;0,700;1,400&display=swap');

:root {
    --bg-light: #f4f4f0;
    --text-light: #1a1a1a;
    --accent-light: #d93025; /* Rock Red */

    --bg-dark: #121212;
    --text-dark: #e0e0e0;
    --accent-dark: #ff4d4d;

    --card-width: 550px;
    --border-radius: 4px;
    --anim-speed: 0.4s;
}

body {
    margin: 0;
    padding: 10px;
    display: flex;
    justify-content: center;
    font-family: 'Courier Prime', monospace;
    background-color: transparent;
}

/* --- Container & Theme --- */
.rock-card {
    width: 100%;
    max-width: var(--card-width);
    position: relative;
    border: 2px solid #000;
    background-color: var(--bg-light);
    color: var(--text-light);
    box-shadow: 4px 4px 0px rgba(0,0,0,1);
    transition: all var(--anim-speed) ease;
    overflow: hidden;
    cursor: pointer;
    user-select: none;
}

/* Dark Mode: Noise Texture */
.rock-card.dark-mode {
    background-color: var(--bg-dark);
    /* CSS Noise Generation */
    background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.65' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)' opacity='0.15'/%3E%3C/svg%3E");
    color: var(--text-dark);
    border-color: #444;
    box-shadow: 4px 4px 0px #000;
}

/* --- Collapsed Player Header --- */
.player-header {
    display: flex;
    align-items: center;
    padding: 15px;
    height: 60px;
    border-bottom: 2px solid transparent;
    transition: border-color var(--anim-speed);
}
.rock-card.expanded .player-header {
    border-bottom: 2px solid currentColor;
}

.play-btn {
    width: 30px;
    height: 30px;
    border: 2px solid currentColor;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    margin-right: 15px;
    flex-shrink: 0;
    transition: transform 0.2s;
}
.play-btn::after {
    content: '';
    display: block;
    width: 0;
    height: 0;
    border-style: solid;
    border-width: 6px 0 6px 10px;
    border-color: transparent transparent transparent currentColor;
    transform: translateX(2px);
}
/* Expanded state turns play button to 'stop/open' indicator */
.rock-card.expanded .play-btn::after {
    width: 10px;
    height: 10px;
    border: none;
    background-color: currentColor;
    transform: none;
}

.track-info {
    flex-grow: 1;
    display: flex;
    flex-direction: column;
    justify-content: center;
    overflow: hidden;
}

.album-title {
    font-family: 'New Rocker', cursive;
    font-size: 1.4em;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    letter-spacing: 1px;
}

.time-stamp {
    font-size: 0.8em;
    opacity: 0.7;
    margin-top: 2px;
    display: flex;
    align-items: center;
    gap: 10px;
}

/* Simulated Progress Bar */
.progress-container {
    height: 4px;
    flex-grow: 1;
    background: rgba(128,128,128,0.3);
    position: relative;
    max-width: 100px;
}
.progress-bar {
    height: 100%;
    width: 0%; /* Starts at 0 */
    background: var(--accent-light);
    transition: width 0.5s;
}
.rock-card.dark-mode .progress-bar { background: var(--accent-dark); }

/* --- Expanded Content --- */
.content-body {
    max-height: 0;
    opacity: 0;
    transition: max-height 0.6s cubic-bezier(0.4, 0, 0.2, 1), opacity 0.4s;
    overflow: hidden;
}
.rock-card.expanded .content-body {
    max-height: 800px;
    opacity: 1;
}

/* Visualizer Area (Staves & Notes) */
.visualizer {
    height: 80px;
    background: rgba(0,0,0,0.03);
    position: relative;
    overflow: hidden;
    margin: 10px 15px;
    border: 1px dashed currentColor;
    opacity: 0.6;
}
.staff-lines {
    position: absolute;
    top: 50%;
    left: 0;
    width: 100%;
    transform: translateY(-50%);
    display: flex;
    flex-direction: column;
    gap: 6px;
}
.line {
    width: 100%;
    height: 1px;
    background-color: currentColor;
    opacity: 0.3;
}

/* Animated CSS Notes (No Emoji) */
.note {
    position: absolute;
    width: 10px;
    height: 8px;
    background: currentColor;
    border-radius: 50%;
    bottom: 30px;
    left: 100%;
    transform: rotate(-15deg);
}
.note::after {
    content: '';
    position: absolute;
    right: 0;
    bottom: 0;
    width: 2px;
    height: 25px;
    background: currentColor;
}
.note::before {
    content: '';
    position: absolute;
    right: 0;
    top: -25px;
    width: 8px;
    height: 4px;
    background: currentColor;
    border-radius: 2px;
    transform: skewY(20deg);
    display: none; /* Only for flagged notes */
}
.note.flag::before { display: block; }

/* Animation Classes */
.rock-card.expanded .note {
    animation: moveLeft 4s linear infinite;
}
.n1 { animation-delay: 0s !important; bottom: 25px; }
.n2 { animation-delay: 1.2s !important; bottom: 45px; }
.n3 { animation-delay: 2.5s !important; bottom: 35px; }

@keyframes moveLeft {
    0% { left: 100%; opacity: 0; }
    10% { opacity: 1; }
    90% { opacity: 1; }
    100% { left: -20px; opacity: 0; }
}

/* Text Content Blocks */
.info-block {
    padding: 10px 20px;
    border-left: 2px solid transparent;
    margin-bottom: 10px;
}

.label {
    font-size: 0.75em;
    text-transform: uppercase;
    letter-spacing: 2px;
    font-weight: bold;
    margin-bottom: 5px;
    color: var(--accent-light);
    display: block;
}
.rock-card.dark-mode .label { color: var(--accent-dark); }

.text-content {
    font-size: 0.95em;
    line-height: 1.5;
}

/* Scene (Context) */
.scene-block .label::before { content: '# '; opacity: 0.5; }

/* Plot (Current Track) */
.plot-block {
    background: rgba(128,128,128,0.05);
    border-left-color: var(--accent-light);
}
.rock-card.dark-mode .plot-block { border-left-color: var(--accent-dark); }

/* Seeds (Hidden Track) */
.seeds-block {
    margin: 10px 20px 20px;
    padding: 15px;
    border: 1px dashed currentColor;
    position: relative;
    display: none; /* JS toggles this */
}
.seeds-block.has-content { display: block; }

.seeds-reveal {
    font-size: 0.8em;
    text-align: center;
    cursor: pointer;
    opacity: 0.7;
    text-decoration: underline;
}
.seeds-content {
    margin-top: 10px;
    font-style: italic;
    display: none;
    color: var(--accent-light);
}
.rock-card.dark-mode .seeds-content { color: var(--accent-dark); }
.seeds-block.revealed .seeds-reveal { display: none; }
.seeds-block.revealed .seeds-content { display: block; animation: fadeIn 0.5s; }

@keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }

/* Theme Toggle Area (Hidden click area top right) */
.theme-trigger {
    position: absolute;
    top: 0;
    right: 0;
    width: 40px;
    height: 40px;
    z-index: 10;
    cursor: cell;
}

</style>
</head>
<body>

<div class="rock-card" id="playerCard">
    <div class="theme-trigger" id="themeToggle" title="Toggle Light/Dark"></div>

    <!-- Collapsed Header -->
    <div class="player-header">
        <div class="play-btn"></div>
        <div class="track-info">
            <div class="album-title">$1</div>
            <div class="time-stamp">
                <span>$2</span>
                <div class="progress-container"><div class="progress-bar"></div></div>
            </div>
        </div>
    </div>

    <!-- Expanded Body -->
    <div class="content-body">
        <!-- Animated Staff -->
        <div class="visualizer">
            <div class="staff-lines">
                <div class="line"></div><div class="line"></div><div class="line"></div><div class="line"></div><div class="line"></div>
            </div>
            <div class="note n1"></div>
            <div class="note flag n2"></div>
            <div class="note n3"></div>
        </div>

        <!-- Scene -->
        <div class="info-block scene-block">
            <span class="label">场景 / Context</span>
            <div class="text-content">$3</div>
        </div>

        <!-- Plot -> Current Track -->
        <div class="info-block plot-block">
            <span class="label">当前曲目 / TRACK</span>
            <div class="text-content">$4</div>
        </div>

        <!-- Seeds -> Hidden Track -->
        <div class="seeds-block" id="seedBox">
            <span class="label">隐藏乐段 / HIDDEN TRACK</span>
            <div class="seeds-reveal">[ 点击揭开隐藏音轨 ]</div>
            <div class="seeds-content">$5</div>
        </div>
    </div>
</div>

<script>
document.addEventListener('DOMContentLoaded', () => {
    const card = document.getElementById('playerCard');
    const themeBtn = document.getElementById('themeToggle');
    const seedBox = document.getElementById('seedBox');
    const seedContent = seedBox.querySelector('.seeds-content');
    const progressBar = card.querySelector('.progress-bar');

    // 1. Handle Hidden Track Logic
    const rawSeed = seedContent.innerHTML.trim();
    if (rawSeed && rawSeed !== 'undefined') {
        seedBox.classList.add('has-content');
        seedBox.addEventListener('click', (e) => {
            e.stopPropagation(); // Don't collapse card
            seedBox.classList.add('revealed');
        });
    }

    // 2. Expand/Collapse Logic
    card.addEventListener('click', (e) => {
        // Ignore clicks on theme toggle
        if (e.target === themeBtn) return;

        card.classList.toggle('expanded');

        // Simulate Progress Bar filling up when playing (expanded)
        if (card.classList.contains('expanded')) {
             progressBar.style.width = '100%';
        } else {
             progressBar.style.width = '30%'; // Paused state
        }
    });

    // 3. Theme Logic
    const toggleTheme = () => {
        const isDark = card.classList.toggle('dark-mode');
        localStorage.setItem('mom_rock_theme', isDark ? 'dark' : 'light');
    };

    // Initialize Theme
    const savedTheme = localStorage.getItem('mom_rock_theme');
    if (savedTheme === 'dark') {
        card.classList.add('dark-mode');
    } else if (savedTheme === 'light') {
        card.classList.remove('dark-mode');
    } else {
        // Auto-detect
        if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
            card.classList.add('dark-mode');
        }
    }

    themeBtn.addEventListener('click', (e) => {
        e.stopPropagation();
        toggleTheme();
    });
});
</script>
</body>
</html>
